// // This module increments the counter value by 1 on every positive edge of CLK or resets to 0 when RST is active.
module down_counter (CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        Q <= 4'b1111;
    end else begin
        Q <= Q - 1;
    end
end

endmodule
